INSERT INTO examples (name, category, framework, files, dependencies, metadata) VALUES ('"smooth-scrolling"', '"Prsnt"', '"vanilla"', '{"demo.css": "a {\n  display: inline-block;\n  width: 50px;\n  text-decoration: none;\n}\n\n.scroll-container {\n  width: 350px;\n  height: 200px;\n  overflow-y: scroll;\n  scroll-behavior: smooth;\n}\n.scroll-page {\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  height: 100%;\n  font-size: 5em;\n}\n\n/*\n * https://vanillajstoolkit.com/reference/javascript-free/smooth-scrolling/\n * The scroll-behavior CSS property tells the browser how to handle scrolling triggered by anchor links and such.\n * The default behavior, auto, is the jump-to-location you\u2019re used to seeing. If you set it to smooth, the browser animates scrolling down the page.\n * If you only want this behavior inside a container, apply it to that element. Otherwise, apply it to the whole document.\n */\n\n/**\n * Smooth scrolling inside an element\n */\n#my-element {\n  width: 1rem;\n  height: 1rem;\n  scroll-behavior: smooth;\n  overflow-y: scroll;\n}\n\n/**\n * Smooth scrolling on the whole document\n */\nhtml {\n  scroll-behavior: smooth;\n}\n\n/*\n * For people prone to motion sickness, \n * this effect can be really jarring, though.\n * \n * Fortunately, users in some browsers/operating systems \n * can express their preference for reduced motion effects with the Reduce Motion API. \n * \n * We can listen for that setting in our CSS, \n * and turn off smooth scrolling for them.\n */\n\n@media screen and (prefers-reduced-motion: reduce) {\n  #my-element {\n    scroll-behavior: auto;\n  }\n\n  html {\n    scroll-behavior: auto;\n  }\n}\n\n/*\n * If you\u2019re using a fixed or sticky header, \n * you can prevent anchor links from scrolling behind it with the scroll-margin-top property.\n * https://gomakethings.com/how-to-prevent-anchor-links-from-scrolling-behind-a-sticky-header-with-one-line-of-css/\n */\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Smooth Scrolling\r\n    </h1>\r\n    <div class=\"scroll-container\">\r\n      <div class=\"scroll-page\" id=\"page-1\">1</div>\r\n      <div class=\"scroll-page\" id=\"page-2\">2</div>\r\n      <div class=\"scroll-page\" id=\"page-3\">3</div>\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Layout/smooth-scrolling"}'), ('"split-screen"', '"Prsnt"', '"vanilla"', '{"demo.css": ".split-screen {\n  display: flex;\n}\n\n.split-screen__half {\n  flex: 1;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Split Screen\r\n    </h1>\r\n    <div class=\"split-screen\">\r\n      <!-- Left content -->\r\n      <div class=\"split-screen__half\">Left</div>\r\n\r\n      <!-- Right content -->\r\n      <div class=\"split-screen__half\">Right</div>\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Layout/split-screen"}'), ('"sticky-footer"', '"Prsnt"', '"vanilla"', '{"demo.css": ".sticky-footer {\n  display: flex;\n  flex-direction: column;\n  height: 100%;\n}\n\n.sticky-footer__header,\n.sticky-footer__footer {\n  flex-shrink: 0;\n}\n\n.sticky-footer__main {\n  flex-grow: 1;\n}\n\n/* The footer always sticks to the bottom if the main content is short. */\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Sticky Footer\r\n    </h1>\r\n    <div class=\"sticky-footer\">\r\n      <header class=\"sticky-footer__header\">Header</header>\r\n      <main class=\"sticky-footer__main\">Main</main>\r\n      <footer class=\"sticky-footer__footer\">Footer</footer>\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Layout/sticky-footer"}'), ('"sticky-header"', '"Prsnt"', '"vanilla"', '{"demo.css": ".sticky-header__header {\n  /* Stick to the top */\n  position: sticky;\n  top: 0;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Sticky Header\r\n    </h1>\r\n    <div>\r\n      <header class=\"sticky-header__header\">Header</header>\r\n      <main>main</main>\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Layout/sticky-header"}'), ('"sticky-sections"', '"Prsnt"', '"vanilla"', '{"demo.css": ".sticky-sections {\n  height: 100%;\n  overflow: scroll;\n}\n\n.sticky-sections__section {\n  /* Take full size */\n  height: 100%;\n  width: 100%;\n\n  /* Stick to the top */\n  position: sticky;\n  top: 0;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Sticky Sections\r\n    </h1>\r\n    <div class=\"sticky-sections\">\r\n      <section class=\"sticky-sections__section\">...</section>\r\n\r\n      <!-- Repeat other sections -->\r\n      ...\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Layout/sticky-sections"}'), ('"transform-centering"', '"Prsnt"', '"vanilla"', '{"demo.css": ".parent {\n  border: 1px solid #9C27B0;\n  height: 250px;\n  position: relative;\n  width: 250px;\n}\n\n.child {\n  left: 50%;\n  position: absolute;\n  top: 50%;\n  transform: translate(-50%, -50%);\n  text-align: center;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Transform centering\r\n    </h1>\r\n    <div class=\"parent\">\r\n      <div class=\"child\">Centered content</div>\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Layout/transform-centering"}'), ('"trim-multiline-text"', '"Prsnt"', '"vanilla"', '{"demo.css": ".excerpt {\n  display: -webkit-box;\n  -webkit-line-clamp: 3;\n  -webkit-box-orient: vertical;\n  overflow: hidden;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Static Template\r\n    </h1>\r\n    <p class=\"excerpt\">\r\n      Lorem ipsum dolor sit amet, consectetur adipiscing elit. Donec euismod\r\n      enim eget ultricies sollicitudin. Nunc aliquam arcu arcu, non suscipit\r\n      metus luctus id. Aliquam sodales turpis ipsum, in vehicula dui tempor sit\r\n      amet. Nullam quis urna erat. Pellentesque mattis dolor purus. Aliquam nisl\r\n      urna, tempor a euismod a, placerat in mauris. Phasellus neque quam,\r\n      dapibus quis nunc at, feugiat suscipit tortor. Duis vel posuere dolor.\r\n      Phasellus risus erat, lobortis et mi vel, viverra faucibus lectus. Etiam\r\n      ut posuere sapien. Nulla ultrices dui turpis, interdum consectetur urna\r\n      tempus at.\r\n    </p>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Layout/trim-multiline-text"}'), ('"truncate-multiline-text"', '"Prsnt"', '"vanilla"', '{"demo.css": ".truncate-text-multiline {\n  position: relative;\n  overflow: hidden;\n  display: block;\n  height: 109.2px;\n  margin: 0 auto;\n  font-size: 26px;\n  line-height: 1.4;\n  width: 400px;\n  background: #f5f6f9;\n  color: #333;\n}\n\n.truncate-text-multiline::after {\n  content: \"\";\n  position: absolute;\n  bottom: 0;\n  right: 0;\n  width: 150px;\n  height: 36.4px;\n  background: linear-gradient(to right, rgba(0, 0, 0, 0), #f5f6f9 50%);\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Truncate multiline text\r\n    </h1>\r\n    <p class=\"truncate-text-multiline\">\r\n      Lorem ipsum dolor sit amet, consetetur sadipscing elitr, sed diam nonumy\r\n      eirmod tempor invidunt ut labore et.\r\n    </p>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Layout/truncate-multiline-text"}'), ('"truncate-text"', '"Prsnt"', '"vanilla"', '{"demo.css": ".truncate-text {\n  overflow: hidden;\n  white-space: nowrap;\n  text-overflow: ellipsis;\n  width: 200px;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Truncate text\r\n    </h1>\r\n    <p class=\"truncate-text\">\r\n      If I exceed one line''s width, I will be truncated.\r\n    </p>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Layout/truncate-text"}'), ('"tip-perfect-nested-border-radius-in-css"', '"Prsnt"', '"vanilla"', '{"demo.css": ".outer {\n  border-radius: 24px;\n  padding: 8px;\n}\n\n.inner {\n  border-radius: 16px;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Tip: Perfect nested border radius in CSS\r\n    </h1>\r\n    <div class=\"outer\">\r\n      <div class=\"inner\"></div>\r\n    </div>\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Tip/tip-perfect-nested-border-radius-in-css"}'), ('"tip-select-any-link-with-css"', '"Prsnt"', '"vanilla"', '{"demo.css": ":any-link {\n  color: #0444f6;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Tip: Select any link with CSS\r\n    </h1>\r\n    <a href=\"#\">Link</a>\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Tip/tip-select-any-link-with-css"}'), ('"tip-style-links-without-a-class"', '"Prsnt"', '"vanilla"', '{"demo.css": "a[href]:not([class]) {\n  color: #0077ff;\n  text-decoration: underline;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Tip: Style links without a class\r\n    </h1>\r\n    <a href=\"#\">Styled Link</a>\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Tip/tip-style-links-without-a-class"}'), ('"tip-use-clamp-in-css-for-responsive-typography"', '"Prsnt"', '"vanilla"', '{"demo.css": "h2 {\n  font-size: clamp(1.5rem, 5vw, 3rem);\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Tip: Use clamp() in CSS for responsive typography\r\n    </h1>\r\n    <h2>Clamp()</h2>\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Tip/tip-use-clamp-in-css-for-responsive-typography"}'), ('"alternating-text"', '"Stateful"', '"vanilla"', '{"demo.css": ".alternating {\n  animation-name: alternating-text;\n  animation-duration: 3s;\n  animation-iteration-count: infinite;\n  animation-timing-function: ease;\n}\n\n@keyframes alternating-text {\n  90% {\n    display: none;\n  }\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Alternating text\r\n    </h1>\r\n    <p>\r\n      I love coding in <span class=\"alternating\" id=\"alternating-text\"></span>.\r\n    </p>\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n", "demo.js": "const texts = [\"Java\", \"Python\", \"C\", \"C++\", \"C#\", \"Javascript\"];\nconst element = document.getElementById(\"alternating-text\");\n\nlet i = 0;\nconst listener = (e) => {\n  i = i < texts.length - 1 ? i + 1 : 0;\n  element.innerHTML = texts[i];\n};\n\nelement.innerHTML = texts[0];\nelement.addEventListener(\"animationiteration\", listener, false);\n"}', '{}', '{"original_path": "Vanilla/Stateful/Animation/alternating-text"}'), ('"height-transition"', '"Stateful"', '"vanilla"', '{"demo.css": ".el {\n  transition: max-height 0.3s;\n  overflow: hidden;\n  max-height: 0;\n}\n\n.trigger:hover > .el {\n  max-height: var(--max-height);\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Height transition\r\n    </h1>\r\n    <div class=\"trigger\">\r\n      Hover me to see a height transition.\r\n      <div class=\"el\">Additional content</div>\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n", "demo.js": "let el = document.querySelector(''.el'');\nlet height = el.scrollHeight;\nel.style.setProperty(''--max-height'', height + ''px'');\n"}', '{}', '{"original_path": "Vanilla/Stateful/Animation/height-transition"}'), ('"scroll-progress-bar"', '"Stateful"', '"vanilla"', '{"demo.css": "body {\n  min-height: 200vh;\n}\n\n#scroll-progress {\n  position: fixed;\n  top: 0;\n  width: 0%;\n  height: 4px;\n  background: #7983ff;\n  z-index: 10000;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Scroll progress bar\r\n    </h1>\r\n    <div id=\"scroll-progress\"></div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n", "demo.js": "const scrollProgress = document.getElementById(''scroll-progress'');\nconst height =\n  document.documentElement.scrollHeight - document.documentElement.clientHeight;\n\nwindow.addEventListener(''scroll'', () => {\n  const scrollTop =\n    document.body.scrollTop || document.documentElement.scrollTop;\n  scrollProgress.style.width = `${(scrollTop / height) * 100}%`;\n});\n"}', '{}', '{"original_path": "Vanilla/Stateful/Animation/scroll-progress-bar"}'), ('"shifting-card"', '"Stateful"', '"vanilla"', '{"demo.css": ".container {\n  display: flex;\n  padding: 24px;\n  justify-content: center;\n  align-items: center;\n  background: #f3f1fe;\n}\n\n.shifting-card {\n  width: 350px;\n  display: flex;\n  flex-direction: column;\n  align-items: center;\n  background: #fff;\n  border-radius: 10px;\n  margin: 0.5rem;\n  transition: transform 0.2s ease-out;\n  box-shadow: 0 0 5px -2px rgba(0, 0, 0, 0.1);\n}\n\n.shifting-card .content {\n  text-align: center;\n  margin: 2rem;\n  line-height: 1.5;\n  color: #101010;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Shifting Card\r\n    </h1>\r\n    <div class=\"container\">\r\n      <div class=\"shifting-card\">\r\n        <div class=\"content\">\r\n          <h3>Card</h3>\r\n          <p>\r\n            Lorem ipsum dolor sit amet consectetur adipisicing elit. Corrupti\r\n            repellat, consequuntur doloribus voluptate esse iure?\r\n          </p>\r\n        </div>\r\n      </div>\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n", "demo.js": "const card = document.querySelector(''.shifting-card'');\nconst { x, y, width, height } = card.getBoundingClientRect();\nconst cx = x + width / 2;\nconst cy = y + height / 2;\n\nconst handleMove = e => {\n  const { pageX, pageY } = e;\n  const dx = (cx - pageX) / (width / 2);\n  const dy = (cy - pageY) / (height / 2);\n  e.target.style.transform =\n    `rotateX(${10 * dy * -1}deg) rotateY(${10 * dx}deg)`;\n};\n\nconst handleOut = e => {\n  e.target.style.transform = ''initial'';\n};\n\ncard.addEventListener(''mousemove'', handleMove);\ncard.addEventListener(''mouseout'', handleOut);\n"}', '{}', '{"original_path": "Vanilla/Stateful/Animation/shifting-card"}'), ('"mouse-cursor-gradient-tracking"', '"Stateful"', '"vanilla"', '{"demo.css": ".mouse-cursor-gradient-tracking {\n  position: relative;\n  background: #7983ff;\n  padding: 0.5rem 1rem;\n  font-size: 1.2rem;\n  border: none;\n  color: white;\n  cursor: pointer;\n  outline: none;\n  overflow: hidden;\n}\n\n.mouse-cursor-gradient-tracking span {\n  position: relative;\n}\n\n.mouse-cursor-gradient-tracking::before {\n  --size: 0;\n  content: '''';\n  position: absolute;\n  left: var(--x);\n  top: var(--y);\n  width: var(--size);\n  height: var(--size);\n  background: radial-gradient(circle closest-side, pink, transparent);\n  transform: translate(-50%, -50%);\n  transition: width 0.2s ease, height 0.2s ease;\n}\n\n.mouse-cursor-gradient-tracking:hover::before {\n  --size: 200px;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Static Template\r\n    </h1>\r\n    <button class=\"mouse-cursor-gradient-tracking\">\r\n      <span>Hover me</span>\r\n    </button>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n", "demo.js": "let btn = document.querySelector(''.mouse-cursor-gradient-tracking'');\nbtn.addEventListener(''mousemove'', e => {\n  let rect = e.target.getBoundingClientRect();\n  let x = e.clientX - rect.left;\n  let y = e.clientY - rect.top;\n  btn.style.setProperty(''--x'', x + ''px'');\n  btn.style.setProperty(''--y'', y + ''px'');\n});\n"}', '{}', '{"original_path": "Vanilla/Stateful/Effect/mouse-cursor-gradient-tracking"}'), ('"typewriter-effect"', '"Stateful"', '"vanilla"', '{"demo.css": ".typewriter-effect {\n  display: flex;\n  justify-content: center;\n  font-family: monospace;\n}\n\n.typewriter-effect > .text {\n  max-width: 0;\n  animation: typing 3s steps(var(--characters)) infinite;\n  white-space: nowrap;\n  overflow: hidden;\n}\n\n.typewriter-effect::after {\n  content: \" |\";\n  animation: blink 1s infinite;\n  animation-timing-function: step-end;\n}\n\n@keyframes typing {\n  75%,\n  100% {\n    max-width: calc(var(--characters) * 1ch);\n  }\n}\n\n@keyframes blink {\n  0%,\n  75%,\n  100% {\n    opacity: 1;\n  }\n  25% {\n    opacity: 0;\n  }\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Static Template\r\n    </h1>\r\n    <div class=\"typewriter-effect\">\r\n      <div class=\"text\" id=\"typewriter-text\"></div>\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n", "demo.js": "const typeWriter = document.getElementById(''typewriter-text'');\nconst text = ''Lorem ipsum dolor sit amet.'';\n\ntypeWriter.innerHTML = text;\ntypeWriter.style.setProperty(''--characters'', text.length);\n"}', '{}', '{"original_path": "Vanilla/Stateful/Effect/typewriter-effect"}'), ('"Image-gallery-with-horizontal-scroll"', '"Stateful"', '"vanilla"', '{"demo.css": ".gallery-container {\n  position: relative;\n  display: flex;\n  justify-content: center;\n}\n\n.thumbnails {\n  position: absolute;\n  bottom: 8px;\n  display: flex;\n  flex-direction: row;\n  gap: 6px;\n}\n\n.thumbnails div {\n  width: 8px;\n  height: 8px;\n  cursor: pointer;\n  background: #aaa;\n  border-radius: 100%;\n}\n\n.thumbnails div.highlighted {\n  background-color: #777;\n}\n\n.slides {\n  margin: 0 16px;\n  display: grid;\n  grid-auto-flow: column;\n  gap: 1rem;\n  width: 540px;\n  padding: 0 0.25rem;\n  height: 720px;\n  overflow-y: auto;\n  overscroll-behavior-x: contain;\n  scroll-snap-type: x mandatory;\n  scrollbar-width: none;\n}\n\n.slides > div {\n  scroll-snap-align: start;\n}\n\n.slides img {\n  width: 540px;\n  object-fit: contain;\n}\n\n.slides::-webkit-scrollbar {\n  display: none;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Static Template\r\n    </h1>\r\n    <div class=\"gallery-container\">\r\n      <div class=\"thumbnails\"></div>\r\n      <div class=\"slides\">\r\n        <div><img src=\"https://picsum.photos/id/1067/540/720\" /></div>\r\n        <div><img src=\"https://picsum.photos/id/122/540/720\" /></div>\r\n        <div><img src=\"https://picsum.photos/id/188/540/720\" /></div>\r\n        <div><img src=\"https://picsum.photos/id/249/540/720\" /></div>\r\n        <div><img src=\"https://picsum.photos/id/257/540/720\" /></div>\r\n        <div><img src=\"https://picsum.photos/id/259/540/720\" /></div>\r\n        <div><img src=\"https://picsum.photos/id/283/540/720\" /></div>\r\n        <div><img src=\"https://picsum.photos/id/288/540/720\" /></div>\r\n        <div><img src=\"https://picsum.photos/id/299/540/720\" /></div>\r\n      </div>\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n", "demo.js": "const slideGallery = document.querySelector(''.slides'');\nconst slides = slideGallery.querySelectorAll(''div'');\nconst thumbnailContainer = document.querySelector(''.thumbnails'');\nconst slideCount = slides.length;\nconst slideWidth = 540;\n\nconst highlightThumbnail = () => {\n  thumbnailContainer\n    .querySelectorAll(''div.highlighted'')\n    .forEach(el => el.classList.remove(''highlighted''));\n  const index = Math.floor(slideGallery.scrollLeft / slideWidth);\n  thumbnailContainer\n    .querySelector(`div[data-id=\"${index}\"]`)\n    .classList.add(''highlighted'');\n};\n\nconst scrollToElement = el => {\n  const index = parseInt(el.dataset.id, 10);\n  slideGallery.scrollTo(index * slideWidth, 0);\n};\n\nthumbnailContainer.innerHTML += [...slides]\n  .map((slide, i) => `<div data-id=\"${i}\"></div>`)\n  .join('''');\n\nthumbnailContainer.querySelectorAll(''div'').forEach(el => {\n  el.addEventListener(''click'', () => scrollToElement(el));\n});\n\nslideGallery.addEventListener(''scroll'', e => highlightThumbnail());\n\nhighlightThumbnail();\n"}', '{}', '{"original_path": "Vanilla/Stateful/Layout/Image-gallery-with-horizontal-scroll"}');